POST /api/v5/device/configure HTTP/1.1
Host: smart-home-controls.cloud
Authorization: Bearer bTxD3VmkF98rypvLqAZCNWTXx7scNLzU
Content-Type: application/json
Accept: application/json
User-Agent: Mozilla/5.0 (Linux; Android 13; SM-G991B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/114.0.5735.51 Mobile Safari/537.36
Content-Length: 365

{
  "deviceId": "SHD-99384",
  "config": {
    "modes": ["eco", "comfort", "away"],
    "sensors": {
      "temperature": {
        "calibration": -0.3,
        "units": "Celsius",
        "thresholds": {"min": 16, "max": 28}
      },
      "humidity": {
        "calibration": 0.5,
        "thresholds": {"min": 30, "max": 60}
      }
    },
    "schedule": [
      {"day": "monday", "start": "06:00", "end": "22:00"},
      {"day": "tuesday", "start": "06:00", "end": "22:00"}
    ]
  }
}

PUT /v1/projects/931f72a9/settings HTTP/1.1
Host: config-management.solutionshub.tech
Authorization: Bearer eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9.MzE5ODc2NTQ3MQ.Xr9RQg-ndNIe59627Y0fWbjgx3zztGI2G_epRvvTG18I
Content-Type: application/json
Accept: application/json
User-Agent: curl/7.84.0
Content-Length: 290

{
  "projectId": "931f72a9",
  "settings": {
    "build": {
      "targets": ["linux-amd64", "windows-x86"],
      "optimization": {
        "level": 3,
        "flags": ["-O3", "-march=native"]
      }
    },
    "deployment": {
      "strategy": "blue-green",
      "autoRollback": true
    }
  }
}

POST /api/v3/account/settings/configure HTTP/1.1
Host: secure-user-portal.net
Authorization: Bearer aS9C2pn9WdQX0oTvLezN56rsKD9YpVqt
Content-Type: application/json
Accept: application/json
User-Agent: Mozilla/5.0 (Macintosh; Intel Mac OS X 13_5) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/16.5 Safari/605.1.15
Connection: keep-alive
Content-Length: 278

{
  "account": {
    "id": 75421,
    "preferences": {
      "themes": ["dark", "high-contrast"],
      "languages": ["en-US", "fr-CA"],
      "notifications": {
        "email": true,
        "push": false,
        "sms": false
      }
    },
    "security": {
      "twoFactorAuth": {
        "enabled": true,
        "methods": ["authenticator_app", "sms"]
      },
      "backupEmails": ["backup1@secureportal.net", "backup2@secureportal.net"]
    }
  }
}

